class Solution {
    public int longestPalindrome(String s, String t) {
        int[][] dp = new int[s.length() + 1][s.length() + 1];
        int max = 0;
        for (int i = s.length(); i >= 0; i--) {
            for (int j = t.length(); j >= 0; j--) {
                if (i < s.length() && j < t.length() && s.charAt(i - 1) == t.charAt(j - 1)) {
                    dp[i][j] = dp[i + 1][j + 1] + 2;
                    if (i == 1 && j == 1) max = dp[i][j];
                } else {
                    dp[i][j] = Math.max(dp[i + 1][j], dp[i][j + 1]);
                }
                if (i == 1 && j == 1) max = Math.max(max, dp[i][j]);
                if (s.charAt(i-1) == t.charAt(j-1)) max = Math.max(max, dp[i+1][j+1]+2);
            }
        }
        int countS[] = new int[26];
        int countT[] = new int[26];
        for (char c : s.toCharArray()) countS[c-'a']++;
        for (char c : t.toCharArray()) countT[c-'a']++;
        for (int i = 0; i < 26; i++) {
            max = Math.max(max, Math.min(countS[i], countT[i])*2);
        }
        return max;
    }
}
